CREATE TABLE IF NOT EXISTS `earthquakes` (
  `erqId` varchar(40) NOT NULL,
  `idEarthquake` int(11) NOT NULL AUTO_INCREMENT,
  `DateTime` double(13,8) DEFAULT NULL,
  `lat` float(13,5) DEFAULT NULL,
  `lon` float(13,5) DEFAULT NULL,
  `depth` float(13,5) DEFAULT NULL,
  `Ml` double DEFAULT NULL,
  `Md` double DEFAULT NULL,
  `StrainMl` double(15,5) DEFAULT NULL,
  `StrainMd` double(15,5) DEFAULT NULL,
  `nl` int(11) DEFAULT NULL,
  `gap` int(11) DEFAULT NULL,
  `rms` float(13,5) DEFAULT NULL,
  `seh` float(13,5) DEFAULT NULL,
  `sez` float(13,5) DEFAULT NULL,
  `q` varchar(1) DEFAULT NULL,
  `sqd` varchar(3) DEFAULT NULL,
  `area` varchar(50) DEFAULT NULL,
  `toponimo` varchar(150) DEFAULT NULL,
  `auser` int(11) DEFAULT NULL,
  `fname` varchar(50) DEFAULT NULL,
  `recDate` datetime DEFAULT NULL,
  `published` varchar(5) NOT NULL DEFAULT 'false',
  `deleted` bit(1) DEFAULT b'0',
  `Mag_Mean` double DEFAULT NULL,
  `Mag_Median` double DEFAULT NULL,
  `Mag_StdDev` double DEFAULT NULL,
  `auser_old` int(11) DEFAULT NULL,
  `UserDefinedWLength` smallint(6) DEFAULT '-2',
  `UserPickingOffset` double DEFAULT '0',
  `Note` varchar(150) DEFAULT NULL,
  `published_bool` bit(1) DEFAULT NULL,
  `POSTED` bit(1) DEFAULT b'0',
  `id_locator` int(11) unsigned DEFAULT NULL,
  PRIMARY KEY (`idEarthquake`),
  UNIQUE KEY `erqId_idx` (`erqId`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=44338 DEFAULT CHARSET=latin1;

